#include "KonbiniUI.h"#include "Utils.h"#include "Colors.h"#include <print>void KonbiniUI::printUserCanChangeLNG() {    Utils::printMsgNLine(possibilityToChoseLng);}void KonbiniUI::printChooseLangMsg() {    Utils::printMsgSpace(langMsg);}void KonbiniUI::printWrongLngInput() {    Utils::printWrongMsgNLine(wrongInputMsg);}void KonbiniUI::printLngMenu() {    for (size_t i{}; i < lngMenu.size(); ++i) {        Utils::printTabOptionNLine(lngMenu[i], i, COLORS::PURPLE);    }}void KonbiniUI::printMenu(const std::vector<std::string_view> &arr) {    for (size_t i{}; i < arr.size(); ++i) {        Utils::printTabOptionNLine(arr[i], i, COLORS::BLU);    }}